+import crypto from "node:crypto";
+
+const oneHourMs = 60 * 60 * 1000;
+
+const secret = () => process.env.NEXT_AUTH_SECRET || "dev-secret";
+
+export function createPasswordResetToken(email: string) {
+  const expiresAt = Date.now() + oneHourMs;
+  const payload = Buffer.from(JSON.stringify({ email, expiresAt })).toString(
+    "base64url",
+  );
+  const signature = crypto
+    .createHmac("sha256", secret())
+    .update(payload)
+    .digest("base64url");
+
+  return `${payload}.${signature}`;
+}
+
+export function verifyPasswordResetToken(token: string) {
+  const [payload, signature] = token.split(".");
+  if (!payload || !signature) return null;
+
+  const expected = crypto
+    .createHmac("sha256", secret())
+    .update(payload)
+    .digest("base64url");
+
+  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
+    return null;
+  }
+
+  const data = JSON.parse(Buffer.from(payload, "base64url").toString("utf8"));
+  return data.expiresAt > Date.now() ? (data.email as string) : null;
+}
